import{c as t,Q as a,j as o,m as n}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"The Rundown AI — 2026-05-03","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-03","date":"2026-05-03T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-03-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-03-the-rundown-ai.md","lastUpdated":1779898012000}'),i={name:"research/ai-news/2026-05/2026-05-03-the-rundown-ai.md"};function r(s,e,h,m,p,l){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-05-03" tabindex="-1">🗞️ The Rundown AI — 2026-05-03 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-03" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-03&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="exclusive-uipath-cmo-michael-atalla-on-ai-at-work" tabindex="-1"><a href="https://www.therundown.ai/p/exclusive-uipath-cmo-michael-atalla-on-ai-at-work" target="_blank" rel="noreferrer">Exclusive: UiPath CMO Michael Atalla on AI at work</a> <a class="header-anchor" href="#exclusive-uipath-cmo-michael-atalla-on-ai-at-work" aria-label="Permalink to &quot;[Exclusive: UiPath CMO Michael Atalla on AI at work](https://www.therundown.ai/p/exclusive-uipath-cmo-michael-atalla-on-ai-at-work)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-03</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=exclusive-uipath-cmo-michael-atalla-on-ai-at-work" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=exclusive-uipath-cmo-michael-atalla-on-ai-at-work" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. AI has changed the world that we live in. Every CEO is talking about AI, and most of their employees are wondering what it means for their paycheck.</p><p>At the center of that shift sits <a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">UiPath</a>, which just marked its five-year IPO anniversary — evolving from a company that once automated tasks to one that now orchestrates how AI agents, automation, and people work together.</p><p>We sat down with the company&#39;s CMO, <a href="https://www.linkedin.com/in/michaeljatalla/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=exclusive-uipath-cmo-michael-atalla-on-ai-at-work" target="_blank" rel="noreferrer">Michael Atalla</a>, to understand what&#39;s really happening inside organizations: why AI promises often fall short, who&#39;s winning, and what it all means for everyone whose job is changing because of this technology.</p><p>In today’s AI rundown:</p><p>Five years in: what&#39;s changed, what hasn&#39;t</p><p>The wall most AI projects never get past</p><p>AI&#39;s job anxiety is real, but so is the nuance</p><p>Where AI takes over — and where it doesn&#39;t</p><p>Quick hits with Michael</p><p>LATEST DEVELOPMENTS</p><p>LESSON FOR AI LEADERS</p><p>📅 <a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">Five years in: what&#39;s changed, what hasn&#39;t</a></p><p><a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer"></a></p><p>The Rundown: UiPath’s pitch five years ago was simple: automate the task. Today it&#39;s something more ambitious — orchestrate how every AI agent, robot, and human in a workflow works together.</p><p>Cheung: Five years ago this week, UiPath rang the IPO bell as the category leader in robotic process automation. Today you&#39;re pitching “agentic business orchestration.” What&#39;s the single biggest thing that has changed about the bet — and what has stayed exactly the same?</p><p>Atalla: Five years ago, the promise was simple: automate the task, free the person. It worked. It still works. But walk into most enterprises today and you&#39;ll find dozens of automations running in parallel with no real way to connect them to each other, or to what the business is actually trying to accomplish.</p><p>The question customers used to ask us was “can we automate this?” The question now is “how do we get all of these things working together?” <a href="https://www.uipath.com/blog/product-and-updates/what-is-boat-business-orchestration-automation-technologies/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">Orchestration is the answer</a>. AI agents, automation, people, and systems running end-to-end, with visibility across the whole thing.</p><p>Atalla added: The bet that hasn&#39;t changed: technology should take friction out of people&#39;s work, not add new kinds of it.</p><p>Cheung: You spent 15 years at Microsoft leading the marketing of Office through its shift from on-premise to cloud-based Office 365. What did that teach you about moving enterprises through a paradigm shift that most AI leaders today are missing?</p><p>Atalla: In 2011, I was demoing Exchange features like &quot;conversation view&quot; and the &quot;Do Not Reply All&quot; button to customers who were skeptical about moving their email off a server they could physically touch. That was my Office 365 education.</p><p>You can have the right product and still lose the customer if you can&#39;t help them rethink how work gets done. We weren&#39;t selling cloud software. We were asking people to change how they collaborated, where they stored information, and whether they trusted a system they couldn&#39;t see.</p><p>AI conversations today fixate on the model. What it can do in theory. Enterprises don&#39;t care about theory. They care whether it works reliably under real conditions, inside real workflows, with real accountability. The companies that got stuck in the cloud transition weren&#39;t short on ambition. They just lifted and shifted without redesigning anything. That same pattern is playing out with AI right now.</p><p>Why it matters: If your team is evaluating AI tools right now, the question to bring to the next vendor meeting needs reframing from “what can this model do?” to “what does our workflow need to look like for this to even work?” Get that wrong, and you might end up as the company in the 70–80% who never make it out of AI pilots.</p><p>AI BARRIER</p><p>‼️ <a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">The wall most AI projects never get past</a></p><p><a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Atalla says the core issue behind lagging AI initiatives is a lack of coordination. Whether in pilot or deployment, tools running in isolation, disconnected from each other and from business goals, is where costs accumulate &amp; ROI disappears.</p><p>Cheung: 70-80% of agentic AI initiatives never even make it out of the pilot stage. What are the honest reasons most companies are failing?</p><p>Atalla: AI pilots almost always run in isolation. One agent in one corner of the business. One automation in another. No visibility between them. The pilot succeeds, leadership asks what&#39;s next, and nobody has a real answer. Costs accumulate. Results are hard to measure. Eventually, somebody decides it wasn&#39;t worth it.</p><p>The organizations getting past that stage aren&#39;t doing anything radical. They stopped treating AI agents as tools to deploy. They started treating them as components of a larger, governed workflow. That&#39;s the whole game.</p><p>Cheung: A survey found nearly half of organizations call AI a &quot;massive disappointment&quot; despite heavy investment. What is going wrong post-deployment?</p><p>Atalla: Nobody sets out to fail at this. The ambition is there all the way down. From the CEO to the person whose Tuesday is supposed to get easier. So when you see numbers like those, it&#39;s almost never a motivation problem.</p><p>What I hear from customers is a coordination problem. They&#39;ve automated tasks. They&#39;ve got AI tools running. But they&#39;re definitely not connected to what the business is trying to accomplish. ROI disappears in that gap.</p><p>The customers who break through start with a different question. Not &quot;which AI tool should we buy?&quot; but &quot;where does work begin, where does it get handed off, where are the decisions getting made?&quot; Start there, and the tech choices get much clearer.</p><p>Why it matters: Coordination is a critical piece of the AI adoption puzzle. Redesigning workflows for AI is important, but the next step is making sure the tools running inside those workflows remain aligned with business goals. Once you crack that, value compounds — every tool becomes more useful as it&#39;s working as part of a system.</p><p>AI IMPACT ON JOBS</p><p>😰 <a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">AI&#39;s job anxiety is real, but so is the nuance</a></p><p><a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer"></a></p><p>The Rundown: With the advances in AI, Atalla acknowledged that the anxiety in the job market is real. However, he pushed back on the idea that human involvement is becoming optional, saying roles are changing shape, not disappearing.</p><p>Cheung: Three-quarters of AI experts are optimistic about AI&#39;s impact on jobs, but only 23% of the public agrees. Who is closer to reality, and why such a disconnect?</p><p>Atalla: Honestly? Both groups are seeing something real. They&#39;re just looking at different parts of the picture. The experts see what the technology is capable of. The end user sees what&#39;s being handed to the technology and wonders what that leaves for them. It&#39;s a reasonable read of the signals.</p><p>What I&#39;d push back on is the idea that human involvement becomes optional as AI gets smarter. An LLM cannot ask &quot;should we?&quot; It has no motivation, no taste, no instinct for risk. Every system we deploy at UiPath still needs humans to oversee it, make judgment calls, and apply it in ways that add value. The role evolves. The need does not go away.</p><p>Cheung: Entry-level dev jobs dropped nearly 20% since 2024 as senior roles grew. UiPath&#39;s CEO himself said the goal is to &quot;grow without growing headcount.&quot; Is the anxiety in the job market justified, or are people worried about the wrong thing?</p><p>Atalla: The anxiety is real, and it deserves to be taken seriously. A meaningful number of entry-level roles are being reshaped right now. That&#39;s not nothing, especially for people who built their career expectations around a different set of conditions.</p><p>The redistribution is more nuanced than the headlines suggest. Routine, structured work is getting absorbed. But the work itself doesn&#39;t disappear. It changes shape. New roles are emerging around workflow design, AI governance, and end-to-end process ownership. The demand is there. The skills being demanded are different.</p><p>My daughter is 13. When she applies to colleges in five years, the jobs she&#39;ll be competing for probably haven&#39;t been named yet. That&#39;s cold comfort if you&#39;re 24 right now. But it&#39;s also not the same thing as replacement.</p><p>Why it matters: Every worker watching AI transform their industry is asking — is my job next? The answer is both yes and no. AI will absorb the routine, structured parts of the work. What it won’t replace is judgment, taste, and instinct, or the parts that require a human to ask &quot;should we?&quot; Now, it’s all about upskilling for the work that&#39;s left.</p><p>UIPATH AI PLAYBOOK</p><p>🤖 <a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">Where AI takes over — and where it doesn&#39;t</a></p><p><a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Atalla says UiPath deploys agents for tasks that involve ambiguity — like interpreting an invoice that doesn&#39;t fit a standard template — while keeping humans on anything that carries real accountability.</p><p>Cheung: What does AI and automation working with people actually look like inside UiPath for someone in finance, or HR, or ops?</p><p>Atalla: Picture a finance team reconciling data across five systems and chasing approvals through email. The automation handles the structured, repeatable parts —pulling data, matching records, and routing requests. An agent steps in where there&#39;s ambiguity — flagging an anomaly, interpreting an invoice that doesn&#39;t fit the standard template. The person in that role stops doing the reconciliation and starts reviewing the exceptions, making the calls that actually require judgment.</p><p>The person&#39;s time shifts toward the things only they can do. That changes how the job feels day to day, which is a bigger deal than it sounds.</p><p>Cheung: With autonomous agent tools gaining serious traction, what kinds of tasks do you think AI agents will actually handle on their own in the next year or two?</p><p>Atalla: The &quot;full autonomy&quot; conversation runs way ahead of what&#39;s actually happening. What I see at UiPath is more specific and, honestly, more interesting.</p><p>Agents are very good at handling unstructured data, making context-aware decisions inside a defined process, and managing exceptions. Think document understanding, fraud detection, and customer service triage. The kind of work where the input isn&#39;t clean, and a rules-based system either fails or needs constant babysitting.</p><p>Deterministic, rules-based work still runs better on traditional automation. And the decisions that carry real accountability, approvals, escalations, anything with consequences, those stay with people.</p><p>The near-term model is agents operating inside orchestrated workflows. More cognitive responsibility. Still governed. Still observable.</p><p>Why it matters: While frontier AI giants continue to talk up full autonomy, UiPath&#39;s approach is more grounded — deploy agents only where they genuinely do well, and humans on higher-value tasks. It&#39;s less exciting, but it keeps the machinery moving with outcomes and is the version of AI adoption that actually holds up.</p><p>LIGHTNING ROUND</p><p>⚡️ <a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer">Quick hits with Michael</a></p><p><a href="https://www.uipath.com/?utm_source=rundownai&amp;utm_medium=paid_web_referral&amp;utm_campaign=advocacy&amp;utm_content=nl&amp;utm_term=rundownai&amp;utm_team=spr&amp;utm_team_geo=global" target="_blank" rel="noreferrer"></a></p><p>The one thing enterprises get wrong about AI more than anything else?</p><p>Atalla: Expecting it to fix a broken process. AI makes good workflows faster and bad ones more expensive.</p><p>What are companies getting wrong in how they introduce AI to their teams?</p><p>Atalla: Framing it as something happening to people rather than something they&#39;ll build with. Anxiety starts in that framing, and it&#39;s usually avoidable.</p><p>If you weren&#39;t at UiPath, what AI problem would you want to be working on?</p><p>Atalla: The gap between what organizations believe AI will do for them and what it&#39;s actually set up to do. That&#39;s a clarity problem, not a technology one. I find it genuinely fascinating.</p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',79)])])}const c=t(i,[["render",r]]);export{d as __pageData,c as default};
